import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './frontend/App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

const express = require('express');
const cors = require('cors');
require('dotenv').config();

const app = express();
const PORT = process.env.PORT || 5000;

// Middlewares
app.use(cors());
app.use(express.json());

// Routes API de base
app.get('/api/health', (req, res) => {
    res.json({ status: 'OK', service: 'EcolePro API', timestamp: new Date() });
});

// Endpoint pour les statistiques globales (Simulé)
app.get('/api/stats', (req, res) => {
    res.json({
        totalStudents: 150,
        totalTeachers: 25,
        monthlyRevenue: 2500000,
        currency: 'FCFA'
    });
});

app.listen(PORT, () => {
    console.log(`Backend EcolePro démarré sur http://localhost:${PORT}`);
});

export enum StudentStatus {
  ACTIVE = 'Actif',
  ABSENT = 'Absent',
  SUSPENDED = 'Suspendu',
  TRANSFERRED = 'Transféré'
}

export type UserRole = 'SUPER_ADMIN' | 'ADMIN' | 'BURSAR' | 'TEACHER' | 'STUDENT' | 'PARENT' | 'LIBRARIAN';

export interface SystemUser {
  id: string;
  schoolId?: string;
  name: string;
  email: string;
  role: UserRole;
  lastLogin: string;
  status: 'ACTIVE' | 'INACTIVE';
  avatarUrl?: string;
}

export interface Student {
  id: string;
  matricule: string;
  schoolId: string;
  firstName: string;
  lastName: string;
  classGrade: string;
  average: number;
  status: StudentStatus;
  attendance: number;
  behaviorNotes: string[];
  parentName: string;
  parentPhone: string;
  photoUrl?: string;
}

export interface Transaction {
  id: string;
  schoolId: string;
  studentName: string;
  amount: number;
  type: string;
  flow: 'IN' | 'OUT';
  date: string;
  status: string;
  paymentMethod: string;
  reference: string;
  description: string;
}

export enum ViewState {
  DASHBOARD = 'DASHBOARD',
  STUDENTS = 'STUDENTS',
  FINANCE = 'FINANCE',
  SETTINGS = 'SETTINGS'
}

export const CURRENCY = 'FCFA';

export const formatCFA = (amount: number): string => {
  return amount.toLocaleString('fr-FR') + ' ' + CURRENCY;
};

export const PAYMENT_METHODS = [
  { id: 'ORANGE', label: 'Orange Money', color: '#ff6600' },
  { id: 'MTN', label: 'MTN Money', color: '#ffcc00' },
  { id: 'MOOV', label: 'Moov Money', color: '#0066cc' },
  { id: 'WAVE', label: 'Wave Money', color: '#00ccff' },
  { id: 'VIREMENT', label: 'Virement Bancaire', color: '#666666' },
  { id: 'TRANSFERT', label: 'Transfert Bancaire', color: '#333333' },
  { id: 'ESPECES', label: 'Espèces', color: '#10b981' }
];

export const MOCK_USER: any = {
  id: 'admin-1',
  name: 'Directeur EcolePro',
  role: 'ADMIN',
  email: 'admin@ecolepro.ci',
  status: 'ACTIVE'
};

import React, { useState } from 'react';
import { ViewState, SystemUser } from './types';
import { MOCK_USER } from './constants';
import { Sidebar } from '../components/Sidebar';
import { Dashboard } from '../components/Dashboard';
import { FinanceManager } from './components/FinanceManager';
import { SettingsManager } from '../components/SettingsManager';
import { LayoutDashboard, Users, CreditCard, Settings, LogOut, Bell, Wifi } from 'lucide-react';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.DASHBOARD);
  const [currentUser] = useState<SystemUser>(MOCK_USER);

  const renderContent = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard stats={{ totalStudents: 150, totalTeachers: 25, averageAttendance: 95, schoolAverage: 14.5 }} />;
      case ViewState.FINANCE:
        return <FinanceManager currentSchoolId="SCHOOL_01" />;
      case ViewState.SETTINGS:
        return <SettingsManager />;
      default:
        return <div className="p-20 text-center text-slate-400 italic">Module {currentView} en cours de développement...</div>;
    }
  };

  return (
    <div className="flex h-screen bg-slate-50 font-sans">
      {/* Sidebar logic handled here locally or by components/Sidebar.tsx */}
      <aside className="w-64 bg-slate-900 text-white flex flex-col shadow-2xl">
        <div className="p-6 flex items-center gap-3 border-b border-slate-800">
           <div className="w-10 h-10 bg-blue-600 rounded-lg flex items-center justify-center font-bold text-xl shadow-lg shadow-blue-900/50">EP</div>
           <div>
             <h1 className="font-extrabold text-lg leading-none">Ecole<span className="text-amber-400">Pro</span></h1>
             <span className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Version Windows 3.0</span>
           </div>
        </div>

        <nav className="flex-1 p-4 space-y-1">
          <button 
            onClick={() => setCurrentView(ViewState.DASHBOARD)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${currentView === ViewState.DASHBOARD ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <LayoutDashboard size={20} /> <span className="font-bold">Tableau de Bord</span>
          </button>
          <button 
            onClick={() => setCurrentView(ViewState.STUDENTS)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${currentView === ViewState.STUDENTS ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Users size={20} /> <span className="font-bold">Élèves</span>
          </button>
          <button 
            onClick={() => setCurrentView(ViewState.FINANCE)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${currentView === ViewState.FINANCE ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <CreditCard size={20} /> <span className="font-bold">Finances</span>
          </button>
          <button 
            onClick={() => setCurrentView(ViewState.SETTINGS)}
            className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all ${currentView === ViewState.SETTINGS ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400 hover:bg-slate-800 hover:text-white'}`}
          >
            <Settings size={20} /> <span className="font-bold">Paramètres</span>
          </button>
        </nav>

        <div className="p-4 border-t border-slate-800">
           <div className="bg-slate-800/50 p-3 rounded-xl flex items-center gap-3 border border-slate-700">
              <div className="w-8 h-8 rounded-full bg-amber-500 flex items-center justify-center font-bold text-slate-900 text-xs uppercase">
                {currentUser.name.slice(0,2)}
              </div>
              <div className="overflow-hidden">
                <p className="text-xs font-bold truncate">{currentUser.name}</p>
                <p className="text-[10px] text-slate-500 truncate uppercase tracking-tighter">{currentUser.role}</p>
              </div>
           </div>
           <button className="w-full mt-4 flex items-center justify-center gap-2 text-slate-500 hover:text-rose-400 py-2 transition-colors text-sm font-bold">
              <LogOut size={16} /> Déconnexion
           </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white border-b border-slate-200 px-8 flex justify-between items-center shrink-0">
          <div className="flex items-center gap-2 text-slate-400 font-bold text-sm">
             MODULE : <span className="text-blue-600">{currentView}</span>
          </div>
          <div className="flex items-center gap-6">
             <div className="flex items-center gap-2 text-emerald-500 font-bold text-xs uppercase tracking-tighter">
                <Wifi size={16} /> En Ligne
             </div>
             <button className="relative text-slate-400 hover:text-slate-600 transition-colors">
                <Bell size={20} />
                <span className="absolute -top-1 -right-1 w-2 h-2 bg-rose-500 rounded-full border-2 border-white"></span>
             </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
           <div className="max-w-7xl mx-auto">
             {renderContent()}
           </div>
        </div>
      </main>
    </div>
  );
};

export default App;
